const BUILDINGS = [
  // BRUTALIST
  { id: "b1", block: "brutalist", name: "Viviendas El Ruedo (M-30)", architect: "F. J. Sáenz de Oíza (con Javier Sáenz Guerra)", year: "1986–1990", address: "Avda. Doctor García Tapia / C. Félix Rodríguez de la Fuente, 28030", barrio: "Moratalaz", metro: "Vinateros (L9)", bus: "30, 32", description: "Arco helicoidal de 600 m y 8 plantas visible desde la M-30, como un anfiteatro romano. Muro austero de ladrillo hacia la autopista; fachada policroma geométrica en el patio interior con jardines y zonas de juego. Túneles peatonales perforan la base ofreciendo acceso parcial al patio.", interior: "Residencial. Sin visitas formales, aunque ha participado en Open House Madrid.", protection: "Premio COAM 1991. Sin BIC formal.", route: 6, lat: 40.4075, lng: -3.6445 },
  { id: "b2", block: "brutalist", name: "Torre BBVA — Castellana 81", architect: "F. J. Sáenz de Oíza (ing. Carlos Fernández Casado)", year: "1978–1981", address: "Paseo de la Castellana, 81, 28046", barrio: "AZCA, Tetuán", metro: "Nuevos Ministerios (L6, L8, L10)", bus: "", description: "Torre de 107 m sobre dos núcleos de hormigón que salvan el túnel ferroviario Atocha–Chamartín, un tour de force estructural. Revestimiento de acero Cor-Ten con pátina oxidada que evoluciona del bronce al óxido. Parasoles verticales en fachada oeste modulan la luz sobre la superficie.", interior: "Oficinas privadas. Abierta ocasionalmente en Open House Madrid. Jardín japonés en planta baja parcialmente visible. Visible libremente desde el complejo AZCA.", protection: "BIC (Bien de Interés Cultural) desde 2019.", route: 3, lat: 40.4505, lng: -3.6925 },
  { id: "b3", block: "rationalist", name: "Gimnasio del Colegio Maravillas", architect: "Alejandro de la Sota", year: "1960–1962", address: "C. Joaquín Costa, 21, 28002", barrio: "Nueva España, Chamartín", metro: "República Argentina (L6)", bus: "", description: "Resuelve un desnivel de 12 m con cerchas monumentales de acero que apilan gimnasio, piscina, aulas y pistas en cubierta. Alberto Campo Baeza lo llamó 'uno de los cinco mejores edificios de España'. Obra maestra de honestidad estructural racionalista: cada elemento portante está expuesto y es legible — puro De la Sota.", interior: "Colegio activo. Sin acceso general; ha participado en Open House Madrid.", protection: "BIC desde 2017.", route: 1, lat: 40.4460, lng: -3.6860 },
  { id: "b4", block: "brutalist", name: "Palacio de Congresos y Exposiciones", architect: "Pablo Pintado Riba", year: "1964–1970", address: "Paseo de la Castellana, 99, 28046", barrio: "Castillejos, Tetuán", metro: "Cuzco (L10)", bus: "", description: "Brutalismo institucional de manual a lo largo de la Castellana: fachadas monumentales de hormigón visto con volúmenes geométricos rotundos. Su elemento más célebre es el mural cerámico de Joan Miró en la fachada exterior, recientemente restaurado.", interior: "Accesible durante eventos. El mural de Miró es visible desde la calle en todo momento y es patrimonio protegido.", protection: "Patrimonio protegido (mural).", route: 3, lat: 40.4560, lng: -3.6920 },
  { id: "b5", block: "brutalist", name: "Torres de Colón", architect: "Antonio Lamela (ing. estructural: Javier Manterola)", year: "1968–1976", address: "C. Génova, 31 / Plaza de Colón, 28001", barrio: "Recoletos, Salamanca", metro: "Colón (L4)", bus: "", description: "Torres gemelas de 23 plantas construidas con técnica revolucionaria de 'estructura suspendida': los pisos cuelgan de cables anclados a una plataforma superior, construidos de arriba abajo — las primeras así en España. La icónica corona verde 'El Enchufe' fue controvertidamente eliminada en la reforma de 2020–2024 y sustituida por volúmenes de vidrio, alterando fundamentalmente su carácter brutalista. El núcleo estructural de hormigón se conserva bajo la nueva piel.", interior: "Edificio de oficinas (actualmente arrendado a Garrigues). Exterior visible libremente desde Plaza de Colón.", protection: "Sin BIC. Objeto de debates patrimoniales en curso.", route: 3, lat: 40.4255, lng: -3.6900 },
  { id: "b6", block: "brutalist", name: "Centro de Formación Profesional Santamarca", architect: "Fernando Moreno Barberá", year: "1970–1972", address: "C. Costa Rica, 30, 28016", barrio: "Hispanoamérica, Chamartín", metro: "Colombia (L8, L9)", bus: "", description: "Dos bloques monumentales de seis plantas en hormigón visto conectados por patios ajardinados, con muros curvos de hormigón organicista (testeros) y lamas metálicas de inspiración japonesa para protección solar. Premiado por el COAM en 1974.", interior: "Centro educativo y oficinas gubernamentales. Exterior libremente visible, interior acceso limitado.", protection: "Sin BIC. Catalogado por COAM. Registro Docomomo Ibérico.", route: 0, lat: 40.4575, lng: -3.6775 },
  { id: "b7", block: "brutalist", name: "Poblado Dirigido de Caño Roto", architect: "Antonio Vázquez de Castro, José Luis Iñiguez de Onzoño", year: "1957–1963 (tres fases)", address: "Avda. Ntra. Sra. de Valvanera / Vía Carpetana / Glorieta de los Cármenes, 28047", barrio: "Caño Roto, Carabanchel", metro: "Vista Alegre (L5)", bus: "", description: "El poblado dirigido más aclamado internacionalmente. Mezcla de casas-patio en L, torres, bloques dúplex-corredor y plazas diseñadas con cuidado alrededor de calles estrechas y arcadas. La retícula estructural vista y las texturas de ladrillo silicocalcáreo crean un carácter 'brutalista-neoplástico'.", interior: "Calles y espacios públicos libremente accesibles.", protection: "Registro Docomomo Ibérico. Documentado en colección Museo Reina Sofía.", route: 6, lat: 40.3830, lng: -3.7450 },
  { id: "b8", block: "brutalist", name: "Colegio Lourdes 'Los Círculos'", architect: "F. J. Sáenz de Oíza", year: "1958 (construido), 1963 (operativo)", address: "C. San Roberto, 8, 28039", barrio: "El Batán, Latina", metro: "Batán (L10)", bus: "", description: "Aulas circulares cilíndricas con un carácter orgánico-brutalista lúdico, las formas redondas firma de Oíza. Parte de la Colonia Nuestra Señora de Lourdes, también diseñada por Oíza para la iniciativa de vivienda social Hogar del Empleado.", interior: "Colegio activo. No accesible en horario escolar. Exterior visible desde la calle.", protection: "Sin BIC. Obra temprana de Oíza cada vez más reconocida.", route: 0, lat: 40.3925, lng: -3.7380 },
  { id: "b9", block: "brutalist", name: "Fundación Fernando Higueras — 'El Rascainfiernos'", architect: "Fernando Higueras (con Lola Botia)", year: "1972–1975", address: "C. Maestro Lasalle, 36, 28016", barrio: "Nueva España, Chamartín", metro: "Pío XII (L9)", bus: "", description: "Casi invisible desde la calle: un 'anti-rascacielos' subterráneo excavado a mano bajo un jardín. Cubo de hormigón de 9×9×7 m, iluminado solo por cinco lucernarios de 2×2 m a nivel de suelo — desde fuera, solo unos cuadrados de vidrio en el césped delatan la vivienda 7 m más abajo. Cuatro muros de hormigón desnudo, sin ventanas, escalera monumental de madera. Una de las primeras casas 'sostenibles' de España, con solo 9 °C de variación térmica anual.", interior: "Visitable con cita previa (Fundación Fernando Higueras, tel. 913 450 755). Participa en Open House Madrid y la Semana Internacional de la Arquitectura. Conserva dibujos, planos y acuarelas de Higueras.", protection: "Sin protección formal.", route: 0, lat: 40.4580, lng: -3.6780 },
  { id: "b10", block: "brutalist", name: "UVA de Hortaleza", architect: "F. Higueras, L. Espinosa, F. Cabrera, L. Crespi, A. Miró, A. Weber", year: "1963", address: "Zona C. Mar de Aral, 28033", barrio: "Hortaleza", metro: "Mar de Cristal (L4, L8)", bus: "", description: "Una de las seis Unidades Vecinales de Absorción construidas para abordar la crisis del chabolismo madrileño. Edificios sobre pilotis con estructura de acero y generosas galerías-corredor protegidas por amplios aleros. Louis Kahn la elogió como uno de los doce conjuntos residenciales más humanos del mundo. Actualmente en proceso de demolición bajo un programa de regeneración urbana.", interior: "Residencial. Calles libremente accesibles (parcialmente en demolición).", protection: "Registro Docomomo Ibérico (parcial). Patrimonio en riesgo.", route: 0, lat: 40.4780, lng: -3.6380 },
  { id: "b11", block: "brutalist", name: "Edificio Castelar", architect: "Rafael de La-Hoz Arderius", year: "1975–1983", address: "Paseo de la Castellana, 36-38, 28046", barrio: "Almagro, Chamberí", metro: "Rubén Darío (L5)", bus: "", description: "Oficinas sofisticadas con elementos prefabricados de hormigón sobre muro cortina frente a la Castellana. Estética corporativa tardo-brutalista refinada de uno de los arquitectos españoles más importantes del siglo XX.", interior: "Oficinas privadas. Sin acceso público.", protection: "Sin BIC formal.", route: 3, lat: 40.4335, lng: -3.6910 },
  { id: "b12", block: "brutalist", name: "Colegio Estudio de Aravaca", architect: "Fernando Higueras, J. A. Fernández Ordóñez", year: "1962–1964", address: "C. Jimena Menéndez Pidal, 7, 28023", barrio: "Aravaca, Moncloa-Aravaca", metro: "—", bus: "161, 162 / Cercanías El Barrial", description: "Higueras diseñó el colegio donde él mismo se educó: aulas en patrón zigzag de diente de sierra, cada una con su propio jardín elevado. Estructura de hormigón visto bajo cubierta árabe a cuatro aguas de teja tradicional. La luz entra por ranuras continuas en la base de los aleros volados.", interior: "Colegio activo. Exterior visible desde la carretera.", protection: "Protegido por el Ayuntamiento de Madrid desde 2002. Catalogado en guía COAM.", route: 0, lat: 40.4520, lng: -3.7680 },
  { id: "b13", block: "brutalist", name: "Viviendas sociales en Orcasur", architect: "F. J. Sáenz de Oíza, José Manuel López-Peláez", year: "c. 1983–1986", address: "Avenida Orcasur, 28041", barrio: "Orcasitas, Usera", metro: "Oporto (L5, L6)", bus: "", description: "Vivienda social tardo-brutalista en la periferia sur de Madrid con la atención característica de Oíza a la relación entre bloques residenciales y espacio público. Construcción honesta en ladrillo y hormigón.", interior: "Calles públicamente accesibles.", protection: "Sin protección formal. Documentado en archivo COAM.", route: 0, lat: 40.3700, lng: -3.7050 },
  { id: "b14", block: "brutalist", name: "Unidad Vecinal Loyola", architect: "F. J. Sáenz de Oíza, J. L. Romany, Eduardo Mangada, Carlos Ferrán", year: "1960", address: "Zona Vía Lusitana / C. Loyola", barrio: "Carabanchel", metro: "Eugenia de Montijo (L5)", bus: "", description: "Bloques de vivienda social adaptados a la topografía con el centro reservado como espacio peatonal. Construidos en ladrillo y hormigón con aleros ligeros reforzados con vidrio y celosías de tendederos comunitarios.", interior: "Calles y zonas comunes públicamente accesibles.", protection: "Catalogado en guía COAM como parte de la obra de vivienda social de Oíza.", route: 0, lat: 40.3810, lng: -3.7280 },
  { id: "b15", block: "brutalist", name: "Colonia del Batán — bloques y torres", architect: "F. J. Sáenz de Oíza y otros (Hogar del Empleado)", year: "1955–1961", address: "Paseo de la Ermita del Santo / C. San Roberto, 28039", barrio: "El Batán, Latina", metro: "Batán (L10)", bus: "", description: "Vivienda social temprana de Oíza con sensibilidad brutalista emergente en ladrillo y hormigón, prefigurando sus obras maestras posteriores. El conjunto forma un barrio planificado coherente junto con el Colegio Lourdes.", interior: "Calles libremente accesibles.", protection: "Sin BIC. Documentado por COAM.", route: 0, lat: 40.3920, lng: -3.7400 },
  { id: "b16", block: "brutalist", name: "Campus UAM Cantoblanco — Facultad de Ciencias", architect: "Varios (concurso 1969; F. Higueras, A. Miró, J. Serrano-Suñer, M. de Oriol accésit)", year: "1969–1975", address: "Ciudad Universitaria de Cantoblanco, Ctra. de Colmenar Viejo, km 15, 28049", barrio: "Cantoblanco", metro: "—", bus: "Cercanías C-4 Cantoblanco Universidad", description: "Múltiples edificios brutalistas de hormigón visto, especialmente las facultades de ciencias. Módulos de hormigón repetitivos y contundentes caracterizan la planificación megaestructural típica de universidades españolas de los 70.", interior: "Accesible en horario académico (L-V 8:00–21:00).", protection: "Sin protección formal.", route: 0, lat: 40.5420, lng: -3.6910 },
  { id: "b17", block: "brutalist", name: "Casa Echevarría", architect: "F. J. Sáenz de Oíza", year: "1972", address: "C. Lamiaco, 27, La Florida, 28023", barrio: "La Florida, Moncloa-Aravaca", metro: "—", bus: "Bus desde Moncloa", description: "Vivienda unifamiliar brutalista en hormigón bruto que muestra el enfoque de Oíza a escala doméstica. Documentada en los estudios de Antón Capitel sobre Oíza.", interior: "Residencia privada. Exterior parcialmente visible desde la calle.", protection: "Catalogado en archivo COAM.", route: 0, lat: 40.4480, lng: -3.7600 },
  { id: "b18", block: "brutalist", name: "Facultad de Óptica y Optometría (UCM)", architect: "Fernando Moreno Barberá", year: "1968", address: "C. Arcos de Jalón, 118, 28037", barrio: "San Blas-Canillejas", metro: "Simancas (L2)", bus: "", description: "Formas geométricas robustas en hormigón visto que tipifican el brutalismo educativo de Moreno Barberá. Usada como localización de rodaje de Valeria (Netflix). Catalogada por COAM como uno de los mejores ejemplos de brutalismo en España.", interior: "Edificio universitario. Zonas comunes accesibles en horario académico.", protection: "Sin protección formal.", route: 0, lat: 40.4250, lng: -3.6140 },
  { id: "b19", block: "brutalist", name: "Viviendas en Monte Esquinza 41", architect: "Javier Carvajal Ferrer", year: "1966–1968", address: "C. Monte Esquinza, 41, 28010", barrio: "Almagro, Chamberí", metro: "Alonso Martínez (L4, L5, L10)", bus: "", description: "Incluido en la base de datos internacional SOS Brutalism. Bloque residencial con singular fachada de hormigón visto, terrazas profundas y juego volumétrico rotundo que trae a Le Corbusier al corazón del elegante barrio de Almagro.", interior: "Edificio residencial. Solo exterior.", protection: "Base de datos SOS Brutalism.", route: 0, lat: 40.4300, lng: -3.6920 },
  { id: "b20", block: "brutalist", name: "Viviendas en Calle Basílica", architect: "Julio Cano Lasso (con Alberto Campo Baeza)", year: "1966–1974", address: "C. Aviador Zorita / Basílica / Edgar Neville, 17–21, 28020", barrio: "Berruguete, Tetuán", metro: "Nuevos Ministerios (L6, L8, L10)", bus: "", description: "Bloque monolítico de ladrillo visto concebido como tallado de una masa única: el salón saliente y las ventanas rítmicas de cada vivienda se hacen legibles en fachada. Considerado el mejor trabajo residencial de Cano Lasso en Madrid.", interior: "Residencial. Solo visible desde vía pública.", protection: "Documentado en guía COAM.", route: 0, lat: 40.4480, lng: -3.6985 },
  { id: "b21", block: "brutalist", name: "Conjunto Residencial en Bellas Vistas", architect: "José Luis González Cruz", year: "1968–1970", address: "Avenida de Pablo Iglesias, Bellas Vistas", barrio: "Bellas Vistas, Tetuán", metro: "Tetuán (L1)", bus: "", description: "El brutalismo lecorbusieriano más puro de Madrid, por el arquitecto que García Alcántara llama 'el brutalista por excelencia'. Publicado en la revista del COAM Arquitectura (nº 375, 2018) como ejemplo definitorio del estilo en el distrito de Tetuán.", interior: "Residencial. Solo exterior.", protection: "Publicado en revista Arquitectura (COAM, 2018).", route: 0, lat: 40.4600, lng: -3.7010 },
  { id: "b22", block: "rationalist", name: "Casa Huarte", architect: "José Antonio Corrales, Ramón Vázquez Molezún", year: "1966", address: "C. Turégano, 1 / Isla de Oza, 7, Urbanización Puerta de Hierro, 28035", barrio: "Aravaca, Moncloa-Aravaca", metro: "—", bus: "Bus desde Moncloa", description: "Una 'ciudadela doméstica' introvertida: muros opacos de ladrillo y setos ocultan una de las mejores casas modernas de España; casi nada es visible desde fuera excepto la puerta de entrada, lo que solo profundiza la mística. Actualmente deshabitada y en venta.", interior: "Sin programa de visitas regular. Se han organizado visitas para estudiantes de arquitectura con cita previa.", protection: "Docomomo International Grado II. Una de solo cinco casas unifamiliares en el registro ibérico.", route: 0, lat: 40.4600, lng: -3.7550 },
  { id: "b23", block: "rationalist", name: "ETSI de Telecomunicación (UPM)", architect: "Javier Carvajal Ferrer, José María García de Paredes", year: "1960–1964 (inaugurada 1965)", address: "Av. Complutense, 30, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Volúmenes prismáticos articulados por patios interiores y corredores escalonados que siguen el terreno, revestidos en bandas horizontales de pizarra, vidrio y metal. Alberga el Museo de Telecomunicación Joaquín Serna.", interior: "Edificio universitario público. Accesible en horario académico. Museo abierto a visitantes.", protection: "Dentro del perímetro BIC de Ciudad Universitaria.", route: 5, lat: 40.4520, lng: -3.7275 },
  { id: "b24", block: "brutalist", name: "ETSI de Caminos, Canales y Puertos (UPM)", architect: "Luis Laorga Gutiérrez, José López Zanón", year: "c. 1968", address: "C. Profesor Aranguren, s/n, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Masivo edificio educativo de hormigón sobrio donde el 'rigor constructivo' de Laorga y la expresión honesta de la estructura crearon uno de los volúmenes académicos más imponentes del campus. Incluido en la base de datos SOS Brutalism.", interior: "Edificio universitario público. Accesible en horario académico.", protection: "Registro Docomomo Ibérico. Base de datos SOS Brutalism.", route: 5, lat: 40.4495, lng: -3.7300 },
  { id: "b25", block: "rationalist", name: "Escuelas de Formación Profesional Industrial de San Blas", architect: "Fernando Moreno Barberá", year: "Fase 1: 1964–1968; Fase 2: 1968–1972", address: "C. Arcos de Jalón, 120, 28037", barrio: "San Blas-Canillejas", metro: "San Blas (L7)", bus: "", description: "Dos bloques paralelos de cinco plantas enmarcando un vacío central cubierto, con generosos muros cortina de vidrio y una retícula estructural rigurosa. Interpretación miesiana de la arquitectura educativa de Moreno Barberá, junto a la Facultad de Óptica del mismo arquitecto.", interior: "IES San Blas activo. Exterior libremente visible; interior en eventos educativos u Open House Madrid.", protection: "Incluido en el Plan Nacional de Patrimonio del S. XX.", route: 0, lat: 40.4245, lng: -3.6130 },
  { id: "b26", block: "rationalist", name: "Colegio Ntra. Sra. Santa María (ahora Colegio Madrid)", architect: "Antonio Fernández Alba", year: "1959–1961", address: "Ronda de Sobradiel, 80, 28043", barrio: "Conde de Orgaz, Hortaleza", metro: "Canillas (L4)", bus: "", description: "Obra temprana pionera de un futuro Premio Nacional de Arquitectura. Muros de ladrillo visto unifican una escuela de planta abierta que combina organicismo nórdico con racionalismo miesiano, anticipando la crisis del modernismo ortodoxo.", interior: "Colegio privado. Visitas casuales no posibles; investigadores de arquitectura con cita.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4570, lng: -3.6350 },
  { id: "b27", block: "brutalist", name: "Jefatura Superior de Policía", architect: "Luis Gay Llacer, Diego Vega Fernández", year: "1975", address: "Av. del Dr. Federico Rubio y Galí, 55", barrio: "Moncloa-Aravaca", metro: "Moncloa (L3, L6)", bus: "", description: "Originalmente diseñada como residencia de estudiantes, su construcción se detuvo y finalmente se reconvirtió en comisaría. Recuerda que el brutalismo no exige hormigón: este imponente edificio logra su fuerza bruta enteramente en ladrillo. Destacado por @madrid_brutalism.", interior: "Comisaría activa. No visitable. Exterior libremente visible.", protection: "Sin protección formal.", route: 0, lat: 40.4395, lng: -3.7190 },
  { id: "b28", block: "brutalist", name: "Tanatorio de la M-30", architect: "Antonio Fernández Alba", year: "1982–1984", address: "C. Salvador de Madariaga, 11, 28027", barrio: "Ciudad Lineal", metro: "Barrio de la Concepción (L7)", bus: "", description: "Complejo tardo-brutalista solemne y horizontal de formas geométricas contenidas, patios interiores y pérgolas cubiertas. Arquitectura de peso simbólico que media entre la función cívica de la muerte y la contemplación, diseñada por un Premio Nacional de Arquitectura.", interior: "Tanatorio principal de Madrid. Abierto 24 h (28 salas de velatorio, capilla multiconfesional, restaurante).", protection: "Sin protección formal.", route: 0, lat: 40.4380, lng: -3.6380 },
  { id: "b29", block: "brutalist", name: "Central Telefónica del Barrio de la Concepción", architect: "Julio Cano Lasso", year: "1969–1972", address: "C. María Nistal, 1, 28027", barrio: "Ciudad Lineal", metro: "Barrio de la Concepción (L7)", bus: "", description: "Fortaleza prismática de ladrillo casi sin ventanas, coronada por dieciséis dramáticas torres-chimenea con rejillas metálicas. Cano Lasso decía que construir estos volúmenes desnudos era 'una alegría para el arquitecto'. Se alza como una ciudadela terrosa entre bloques de viviendas, su silencio brutal protegiendo equipos sensibles de telecomunicaciones.", interior: "Instalación activa de Telefónica. No abierta al público.", protection: "Sin protección formal. Destacado por @madrid_brutalism.", route: 0, lat: 40.4380, lng: -3.6330 },
  { id: "b30", block: "brutalist", name: "Estación de Chamartín (Madrid-Chamartín-Clara Campoamor)", architect: "J. A. Corrales, R. Vázquez Molezún, J. A. Pruneda, R. Olalquiaga", year: "1972–1975", address: "Agustín de Foxá, s/n, 28036", barrio: "Chamartín", metro: "Chamartín (L1, L10)", bus: "", description: "Bóvedas masivas de hormigón de cañón cubren el vestíbulo principal de una de las dos grandes estaciones de Madrid. El interior monumental de hormigón visto, de aire casi soviético, es obra de los mismos arquitectos del Pabellón de los Hexágonos, aplicando su osadía estructural a la infraestructura civil.", interior: "Estación ferroviaria pública. Acceso libre.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4720, lng: -3.6825 },
  { id: "b31", block: "brutalist", name: "Oficinas en Serrano 69", architect: "Fernando Higueras, Julio Martínez Calzón", year: "1979–1989", address: "C. Serrano, 69, 28006", barrio: "Castellana, Salamanca", metro: "Rubén Darío (L5)", bus: "", description: "Aberturas arqueadas de hormigón prefabricado con jardineras integradas en fachada: el brutalismo orgánico firma de Higueras llevado a la calle comercial más lujosa de Madrid. Antigua sede del Consorcio de Compensación de Seguros. La vegetación se ha deteriorado, recordando el destino del Edificio Princesa.", interior: "Edificio de oficinas. Solo exterior.", protection: "Sin protección formal.", route: 0, lat: 40.4330, lng: -3.6835 },
  { id: "b32", block: "brutalist", name: "Polideportivo del Instituto Ramiro de Maeztu", architect: "Antonio Vázquez de Castro, José Luis Íñiguez de Onzoño", year: "c. 1974", address: "Esquina C. Serrano con C. Jorge Manrique", barrio: "Castellana, Salamanca", metro: "República Argentina (L6)", bus: "", description: "Pabellón deportivo muscular de hormigón armado con iluminación cenital, construido sobre la antigua pista de balonmano de uno de los institutos más prestigiosos de Madrid. Tres niveles de instalaciones deportivas (baloncesto, balonmano, piscina) comprimidos en un volumen imponente en la elegante Calle Serrano.", interior: "Instalación deportiva escolar. No abierta al público en general.", protection: "Sin protección formal.", route: 0, lat: 40.4420, lng: -3.6830 },

  // RATIONALIST
  { id: "r1", block: "rationalist", name: "Gasolinera Porto Pi", architect: "Casto Fernández-Shaw", year: "1927 (reconstruida 1996 tras demolición parcial de 1977)", address: "C. Alberto Aguilera, 18 (esq. Vallehermoso), 28015", barrio: "Gaztambide, Chamberí", metro: "Quevedo (L2)", bus: "", description: "Hito futurista en miniatura: la marquesina de hormigón recuerda un ala de avión, la torre evoca la chimenea de un barco. Considerada una de las tres obras fundacionales de la arquitectura moderna española. Sigue funcionando como gasolinera.", interior: "Exterior visible 24/7.", protection: "Expediente BIP iniciado 2016. Registro Docomomo Ibérico.", route: 2, lat: 40.4290, lng: -3.7110 },
  { id: "r2", block: "rationalist", name: "Hipódromo de la Zarzuela", architect: "Carlos Arniches, Martín Domínguez (arq.); Eduardo Torroja (ing.)", year: "1935; terminado 1941; restaurado 2004–2016", address: "Avda. Padre Huidobro, s/n (A-6, km 8), 28023", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "—", bus: "658 desde Moncloa; lanzadera gratis días de carreras", description: "Las tribunas se coronan con sobrecogedoras cubiertas laminares hiperbólicas de solo 5 cm de espesor que parecen flotar ingrávidas: obra maestra de ingeniería de Torroja y una de las estructuras de cáscara fina más icónicas del mundo.", interior: "Abierto días de carreras (desde 15 €). Hipotour arquitectónico antes de las carreras (~1 h). Museo Eduardo Torroja bajo tribunas norte, gratis dom. de carreras; visitas guiadas 3 € con cita. Temporada: marzo–diciembre.", protection: "BIC (Monumento) desde 2009. Registro Docomomo Ibérico.", route: 5, lat: 40.4710, lng: -3.7570 },
  { id: "r3", block: "rationalist", name: "Casa de las Flores", architect: "Secundino Zuazo (con Michael Fleischer)", year: "1930–1932", address: "C. Rodríguez San Pedro 70-72 / Meléndez Valdés 59-61 / Gaztambide 15-23 / Hilarión Eslava 2-6, 28015", barrio: "Gaztambide, Chamberí", metro: "Argüelles (L3, L4, L6)", bus: "", description: "Manzana completa racionalista en ladrillo cerámico madrileño con arcos elípticos en arcadas de planta baja. Tres patios interiores ajardinados que revolucionaron el modelo de vivienda madrileño. Placa conmemorativa de la residencia de Pablo Neruda aquí en 1934.", interior: "Residencial. Patios cerrados. Exterior visible desde todas las calles circundantes.", protection: "Monumento Nacional (BIC) desde 1981. Registro Docomomo Ibérico.", route: 2, lat: 40.4330, lng: -3.7120 },
  { id: "r4", block: "rationalist", name: "Edificio Capitol (Edificio Carrión)", architect: "Luis Martínez-Feduchi, Vicente Eced", year: "1931–1933", address: "Gran Vía, 41, 28013", barrio: "Sol, Centro", metro: "Callao (L3, L5)", bus: "", description: "El edificio modernista más icónico de Madrid: cuña expresionista de 54 m en la confluencia de Gran Vía y Jacometrezo, coronada por el legendario neón de Schweppes. Fachada aerodinámica de granito y mármol inspirada en Erich Mendelsohn.", interior: "Hotel Vincci Capitol (escalera original años 30, terraza-bar en azotea con vistas a Gran Vía). Cine Capitol abierto durante proyecciones.", protection: "BIC (Monumento) desde 2018. Registro Docomomo Ibérico.", route: 4, lat: 40.4200, lng: -3.7065 },
  { id: "r5", block: "rationalist", name: "Cine Barceló / Teatro Barceló", architect: "Luis Gutiérrez Soto", year: "1930–1931", address: "C. Barceló, 11, 28004", barrio: "Justicia, Centro", metro: "Tribunal (L1, L10)", bus: "", description: "Deslumbrante edificio streamline-moderne con esquina achaflanada curva, líneas aerodinámicas horizontales y perfil de transatlántico influido por Mendelsohn. Tan ejemplar que se publicó en Architects' Data de Ernst Neufert.", interior: "Discoteca Teatro Barceló (jue–sáb noches; teatrobarcelo.com). Interior sustancialmente modificado pero volumen principal preservado.", protection: "BIC (Monumento) desde mayo 2023. Registro Docomomo Ibérico.", route: 2, lat: 40.4255, lng: -3.7005 },
  { id: "r6", block: "rationalist", name: "Nuevos Ministerios", architect: "Secundino Zuazo (original); terminado posguerra", year: "1933–1942", address: "Paseo de la Castellana, 67, 28071", barrio: "Almagro, Chamberí", metro: "Nuevos Ministerios (L6, L8, L10)", bus: "", description: "Vasto complejo gubernamental con galerías porticadas monumentales a lo largo de la Castellana, combinando planificación racionalista con grandeza clasicista inspirada en El Escorial. Usado como 'Banco de España' en La Casa de Papel.", interior: "Oficinas gubernamentales: acceso restringido. La Arquería de Nuevos Ministerios (galería de exposiciones): mar–sáb 11:00–20:00, dom y festivos 11:00–15:00, entrada gratuita.", protection: "Protegido bajo el PGOU de Madrid.", route: 3, lat: 40.4470, lng: -3.6930 },
  { id: "r7", block: "rationalist", name: "Colonia El Viso", architect: "Rafael Bergamín (con Luis Blanco-Soler, Luis Felipe Vivanco)", year: "1933–1936", address: "Calles en torno a Serrano alto: C. Daniel Urrabieta, Tormes, Sil, Nervión, Arga, Turia…, 28002", barrio: "El Viso, Chamartín", metro: "República Argentina (L6)", bus: "", description: "Rara colonia-jardín racionalista superviviente: villas cúbicas de estuco blanco con cubiertas planas, barandillas de tubo de acero y ventanas horizontales inspiradas en Adolf Loos. Originalmente concebida como vivienda asequible, hoy uno de los barrios más caros de Madrid.", interior: "Residencias privadas. Calles paseables libremente.", protection: "Catálogo de Edificios Protegidos del Ayto. de Madrid. Registro Docomomo Ibérico y Plan Nacional del Patrimonio Cultural del S. XX.", route: 1, lat: 40.4440, lng: -3.6830 },
  { id: "r8", block: "rationalist", name: "Residencia de Estudiantes", architect: "Antonio Flórez Urdapilleta", year: "1913–1915", address: "C. del Pinar, 21-23, 28006", barrio: "El Viso, Chamartín", metro: "Gregorio Marañón (L7, L10)", bus: "", description: "Campus de edificios austeros de ladrillo en la 'Colina de los Chopos' (bautizada por Juan Ramón Jiménez), donde vivieron Lorca, Dalí y Buñuel. El edificio 'Transatlántico' debe su nombre a su perfil de barco. Proto-moderno, críticamente vinculado al Movimiento Moderno.", interior: "Exposiciones en Pabellón Transatlántico: lun–sáb 11:00–20:00, dom 11:00–15:00, entrada gratuita. Visitas guiadas con cita previa.", protection: "BIC (Monumento) desde 2025. Sello de Patrimonio Europeo (2015).", route: 1, lat: 40.4405, lng: -3.6855 },
  { id: "r9", block: "rationalist", name: "Cine Europa", architect: "Luis Gutiérrez Soto", year: "1928–1929", address: "C. Bravo Murillo, 160, 28020", barrio: "Berruguete, Tetuán", metro: "Cuatro Caminos (L1, L2, L6)", bus: "", description: "Predecesor del Cine Barceló con fuerte influencia expresionista mendelsohniana: ventanas curvas de galería, retranqueo escalonado del piso superior. Una restauración de fachada en 2021 recuperó la marquesina curva original pese a la conversión del interior en tienda de fontanería. Placa COAM en la fachada.", interior: "Ahora tienda de suministros de fontanería. Fachada visible en horario comercial.", protection: "Protección integral bajo el PGOU de Madrid.", route: 2, lat: 40.4590, lng: -3.7030 },
  { id: "r10", block: "rationalist", name: "Mercado de Maravillas", architect: "Pedro Muguruza", year: "1935–1942", address: "C. Bravo Murillo, 122, 28020", barrio: "Berruguete, Tetuán", metro: "Alvarado (L1)", bus: "", description: "El mayor mercado cubierto municipal de España y uno de los más grandes de Europa: cubierta en diente de sierra con espectacular iluminación cenital. Fachada casi sin decoración = puro diseño racionalista de mercado.", interior: "Abierto al público: lun–vie 9:00–14:00 y 17:00–20:00; sáb 9:00–14:30. Más de 250 puestos. Entrada libre.", protection: "Nivel de Protección 3 bajo el PGOU.", route: 2, lat: 40.4545, lng: -3.7025 },
  { id: "r11", block: "rationalist", name: "Facultad de Filosofía y Letras (UCM)", architect: "Agustín Aguirre (ing. Eduardo Torroja)", year: "1932–1936; reconstruida 1941–42", address: "Plaza de Menéndez Pelayo, s/n, Ciudad Universitaria, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Hito de la arquitectura universitaria racionalista en ladrillo madrileño con pórtico monumental y tambor semicircular del Salón de Actos. Vidriera Art Déco en el vestíbulo y primer ascensor paternóster de España. Donde enseñaron Ortega y Gasset y María Zambrano.", interior: "Edificio UCM activo en horario universitario. Aula Histórica Américo Castro (4.ª planta) reproduce un aula de 1933.", protection: "BIC (Monumento) desde 2017.", route: 5, lat: 40.4465, lng: -3.7270 },
  { id: "r12", block: "rationalist", name: "Viaducto de Segovia", architect: "Francisco Javier Ferrero (ings. Luis Aldaz, José de Juan-Aracil)", year: "1931–1934; restaurado 1977–78", address: "Calle de Bailén sobre Calle de Segovia, 28005", barrio: "Palacio, Centro", metro: "La Latina (L5)", bus: "", description: "Dramático puente racionalista con tres arcos de hormigón armado a 23 m sobre la calle de Segovia. Hormigón pulido con detalles Art Déco. Vistas espectaculares del Palacio Real y la Casa de Campo.", interior: "Accesible 24/7 como puente peatonal y de tráfico.", protection: "Protegido bajo el PGOU y la Ley de Patrimonio Histórico.", route: 4, lat: 40.4135, lng: -3.7135 },
  { id: "r13", block: "rationalist", name: "Residencia de Señoritas — Pabellón Arniches & Domínguez", architect: "Carlos Arniches, Martín Domínguez", year: "1932", address: "C. Fortuny, 53, 28010", barrio: "Almagro, Chamberí", metro: "Rubén Darío (L5)", bus: "", description: "Pabellón racionalista en L descrito como 'uno de los edificios de inspiración Bauhaus más significativos de España': cuatro plantas de ladrillo limpio con ventanas horizontales y barandillas de tubo de acero.", interior: "Sede de la Fundación Ortega-Marañón con exposiciones y conferencias. Consultar fogm.es.", protection: "Sello de Patrimonio Europeo (complejo Residencia de Estudiantes).", route: 0, lat: 40.4330, lng: -3.6920 },
  { id: "r14", block: "rationalist", name: "Casa del Marqués de Villora", architect: "Rafael Bergamín", year: "1927–1929", address: "C. Serrano, 130, 28006", barrio: "El Viso, Chamartín", metro: "República Argentina (L6)", bus: "", description: "Una de las tres obras fundacionales de la arquitectura moderna española. Villa racionalista pionera que combina magistralmente simplicidad funcional con ladrillo cerámico de calidad. Los volúmenes limpios marcaron una ruptura radical con los estilos ornamentales predominantes.", interior: "Residencia privada. Visible desde la calle.", protection: "Catálogo de Edificios Protegidos del área de El Viso.", route: 1, lat: 40.4430, lng: -3.6830 },
  { id: "r15", block: "rationalist", name: "Colonia Parque Residencia", architect: "Rafael Bergamín, Luis Blanco-Soler", year: "1931–1932", address: "Calles junto a Serrano alto (C. Arga, Segre…), 28002", barrio: "El Viso, Chamartín", metro: "República Argentina (L6)", bus: "", description: "Predecesora y compañera de la Colonia El Viso: casas cúbicas de estuco blanco con cubiertas planas, ventanas-banda y barandillas tubulares de acero que demuestran temprana austeridad loosiana.", interior: "Residencias privadas. Calles paseables.", protection: "Catálogo de patrimonio del Ayto. de Madrid.", route: 1, lat: 40.4435, lng: -3.6835 },
  { id: "r16", block: "rationalist", name: "Mercado de Legazpi / Matadero Madrid", architect: "F. J. Ferrero (mercado 1926–35); Luis Bellido (matadero 1911–25)", year: "1911–1935", address: "Plaza de Legazpi / Paseo de la Chopera, 28045", barrio: "Legazpi, Arganzuela", metro: "Legazpi (L3, L6)", bus: "", description: "Mercado racionalista industrial masivo con estructura de hormigón armado y cubierta en diente de sierra, hoy parte del complejo cultural Matadero Madrid, uno de los centros de artes contemporáneas más importantes de la ciudad.", interior: "Mar–dom, horarios variables por espacio; entrada gratuita en la mayoría de exposiciones. Nave de Motores abierta en jornadas especiales.", protection: "Catálogo de patrimonio del Ayto. de Madrid (conjunto Matadero).", route: 6, lat: 40.3920, lng: -3.6970 },
  { id: "r17", block: "rationalist", name: "Central Térmica de Ciudad Universitaria", architect: "Manuel Sánchez Arcas (ing. Eduardo Torroja)", year: "1932–1935", address: "Ciudad Universitaria, cerca de Avda. Complutense, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Edificio industrial funcionalista con expresión honesta de cáscara de hormigón y elementos de acero, representando el enfoque racionalista de las estructuras utilitarias.", interior: "Generalmente no abierto; posible en Open House Madrid.", protection: "Protección general del conjunto de Ciudad Universitaria. Documentación Docomomo Ibérico.", route: 5, lat: 40.4440, lng: -3.7290 },

  // CHURCHES
  { id: "c1", block: "churches", name: "Iglesia de San Agustín", architect: "Luis Moya Blanco", year: "1946–1950", address: "C. Joaquín Costa, 10, 28036", barrio: "El Viso, Chamartín", metro: "Cruz del Rayo (L10)", bus: "", description: "Planta elíptica cubierta por una extraordinaria bóveda de ladrillo con arcos entrecruzados, construida sin acero ni hormigón armado por la escasez material de posguerra (bóvedas tabicadas). Moya reinterpretó conceptos espaciales renacentistas y barrocos con técnica constructiva innovadora. El interior logra una unidad poderosa con el espacio elíptico enfocado hacia el altar.", interior: "Abierta para misa: mañanas y tardes.", protection: "BIC (Monumento) por Decreto 39/2019, Comunidad de Madrid.", route: 1, lat: 40.4455, lng: -3.6860 },
  { id: "c2", block: "churches", name: "Iglesia de Santa Rita (Agustinos Recoletos)", architect: "Antonio Vallejo Álvarez, Fernando Ramírez de Dampierre", year: "1953–1959", address: "C. Gaztambide, 75, 28015", barrio: "Gaztambide, Chamberí", metro: "Islas Filipinas (L7)", bus: "", description: "Oculta tras una fachada residencial de ladrillo, el interior revela una nave perfectamente circular cubierta por cúpula rebajada que se eleva aproximadamente 80 m. 16 muros-aleta de hormigón irradian del suelo al techo; vidrieras de colores cambiantes (dorado-sur, violeta-norte, rojo-este). Anticipa notablemente los conceptos espaciales del Vaticano II una década antes del Concilio.", interior: "Abierta para misa: lun–sáb mañanas y tardes.", protection: "Guía COAM y Docomomo Ibérico. Sin BIC formal.", route: 2, lat: 40.4340, lng: -3.7150 },
  { id: "c3", block: "churches", name: "Capilla del Espíritu Santo (CSIC)", architect: "Miguel Fisac", year: "1942–1943", address: "C. Serrano, 117, 28006", barrio: "El Viso, Chamartín", metro: "República Argentina (L6)", bus: "", description: "Primera gran obra de Fisac: conversión del auditorio de la Residencia de Estudiantes en capilla con bóvedas vaídas y cúpula esférica con linterna. Frescos de Ramón Stolz y relieves de Juan de Adsuara. Prefigura ya la exploración vital de Fisac del espacio sacro.", interior: "L-V 7:30–8:30, 10:00–13:00, 18:00–21:30; dom 10:30–14:00.", protection: "Parte del complejo patrimonial del CSIC.", route: 1, lat: 40.4400, lng: -3.6840 },
  { id: "c4", block: "churches", name: "Centro Parroquial de Santa María Magdalena", architect: "Miguel Fisac", year: "1966–1968", address: "C. Drácena, 23, 28016", barrio: "Nueva España, Chamartín", metro: "Pío XII (L9)", bus: "", description: "Concepto 'muro dinámico' firma de Fisac: un muro curvo liso guía la mirada al altar mientras el muro opuesto texturado admite luz por aperturas estratégicas. Cubierta con las patentadas 'vigas hueso' de hormigón pretensado.", interior: "Parroquia activa.", protection: "Bien Catalogado por la Comunidad de Madrid.", route: 1, lat: 40.4620, lng: -3.6780 },
  { id: "c5", block: "churches", name: "Parroquia Ntra. Sra. Flor del Carmelo", architect: "Miguel Fisac", year: "1983–1990", address: "Avda. de El Ferrol, 49, 28029", barrio: "Barrio del Pilar, Fuencarral–El Pardo", metro: "Barrio del Pilar (L9)", bus: "", description: "Una de las últimas grandes obras religiosas de Fisac. Paneles de 'hormigón con encofrado flexible' patentado por Fisac, con textura acolchada decorada con estrellas carmelitas de ocho puntas. Planta pentagonal irregular con vigas Vierendeel que generan formas retorcidas hacia un lucernario cuadrado en el vértice.", interior: "Parroquia activa. Despacho: lun–vie 12:00–13:00 y 17:30–20:30.", protection: "Sin BIC. Reconocida por Docomomo y Fundación Fisac.", route: 0, lat: 40.4780, lng: -3.7080 },
  { id: "c6", block: "churches", name: "Iglesia de los Sagrados Corazones", architect: "Rodolfo García-Pablos", year: "1961–1965", address: "Plaza de los Sagrados Corazones, s/n (con C. Padre Damián), 28036", barrio: "Hispanoamérica, Chamartín", metro: "Santiago Bernabéu (L10)", bus: "", description: "Estructura poligonal de ladrillo y metal influida por el Pabellón Español de la Expo de Bruselas 1958. Campanile exento de acero de 50 m y franja continua de vidrieras decorativas. Obras notables de Vaquero Turcios, José Luis Sánchez y Amadeo Gabino.", interior: "Parroquia activa.", protection: "Guía COAM. Sin BIC formal.", route: 0, lat: 40.4580, lng: -3.6850 },
  { id: "c7", block: "churches", name: "Parroquia de Nuestra Señora de la Paz", architect: "Rodolfo García-Pablos", year: "1939–1958 (iglesia 1953–58)", address: "C. Valderribas, 37, 28007", barrio: "Pacífico, Retiro", metro: "Pacífico (L1, L6)", bus: "", description: "La primera parroquia creada en Madrid tras la Guerra Civil. Su larga gestación documenta la evolución del historicismo imperial al modernismo temprano: cerchas metálicas, bóveda artesonada, capillas laterales circulares inscritas en contrafuertes y campanario exento.", interior: "Misas: L-V 8:00, 9:00, 11:00, 19:00; dom 9:00, 11:00, 12:00, 13:00, 17:00, 20:00.", protection: "Guía COAM.", route: 0, lat: 40.4060, lng: -3.6730 },
  { id: "c8", block: "churches", name: "Iglesia de Ntra. Sra. de la Fuencisla (Almendrales)", architect: "José María García de Paredes", year: "1961–1965", address: "Plaza Angélica Señora, 1, 28026", barrio: "Almendrales, Usera", metro: "Almendrales (L3)", bus: "", description: "Obra maestra de arquitectura sacra modular: 51 módulos idénticos de pirámide truncada invertida forman la cubierta, cada uno con luz cenital, apoyados en esbeltas columnas de acero como un 'bosque'. El espacio plano y horizontal evoca deliberadamente una mezquita; la entrada perpendicular disuelve el eje basilical. Muros de ladrillo desnudo, sin decoración aplicada.", interior: "Parroquia activa.", protection: "Registro Docomomo Ibérico. Monografía COAM (2002).", route: 6, lat: 40.3785, lng: -3.6970 },
  { id: "c9", block: "churches", name: "Complejo Parroquial de Ntra. Sra. de la Luz", architect: "José Luis Fernández del Amo", year: "1967", address: "C. Fernán Núñez, 4, 28016", barrio: "Hispanoamérica, Chamartín", metro: "Colombia (L8, L9)", bus: "", description: "Primera iglesia postconciliar de Fernández del Amo en Madrid. Intencionadamente anti-monumental desde fuera: muros cerrados de ladrillo sin fachada visible. La obra maestra es el interior: una cubierta 'invertida' recoge luz natural y la dirige al altar y al crucifijo. Austeridad material extrema con manipulación lumínica inteligente que crea un espacio de meditación etéreo y abstracto.", interior: "Parroquia activa.", protection: "Registro Docomomo Ibérico y guía COAM.", route: 0, lat: 40.4555, lng: -3.6785 },
  { id: "c10", block: "churches", name: "Iglesia de Ntra. Sra. del Tránsito (Canillas)", architect: "Luis Cubillo de Arteaga", year: "1961–1963", address: "Carretera de Canillas, 40, 28043", barrio: "Canillas, Hortaleza", metro: "Esperanza (L4)", bus: "", description: "Construida para el Poblado Dirigido de Canillas, adopta la forma radical de una tienda de campaña muy empinada (la Tienda del Encuentro veterotestamentaria) con cerchas trianguladas de acero que brotan del suelo. Pantocrátor monumental de vidrieras de Arcadio Blasco en el muro sur; lucernario cenital en cumbrera dirige luz al altar.", interior: "Parroquia activa.", protection: "Registro Docomomo Ibérico y Plan Nacional del Patrimonio Cultural del S. XX.", route: 0, lat: 40.4600, lng: -3.6390 },
  { id: "c11", block: "churches", name: "Parroquia de San Fernando", architect: "Luis Cubillo de Arteaga", year: "c. 1969–1970", address: "Avda. Alberto Alcocer, 9, 28036", barrio: "Nueva España, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Solución postconciliar de Cubillo para insertar una iglesia en un solar entre medianeras: templo en planta baja, residencias parroquiales arriba igualando la altura de los pisos vecinos. Fachada ciega a la calle; toda la luz entra por patios interiores. Líneas limpias, materiales estructurales vistos, disposición post-Vaticano II.", interior: "Parroquia activa.", protection: "Catalogado en COAM.", route: 0, lat: 40.4580, lng: -3.6870 },
  { id: "c12", block: "churches", name: "Iglesia del Stmo. Cristo de la Misericordia (San Blas)", architect: "José Antonio Corrales", year: "c. 1968–1974", address: "C. Alconera, Barrio de Gran San Blas, 28037", barrio: "San Blas-Canillejas", metro: "San Blas (L7)", bus: "", description: "Diseñada por una mitad del legendario tándem Corrales y Molezún (Pabellón de Bruselas 1958). Cubierta metálica ligera característica de Corrales, retículas estructurales geométricas y ausencia total de ornamento: la arquitectura misma crea la atmósfera espiritual. Ubicada dentro del conjunto de vivienda social de Gran San Blas que Corrales codiseñó.", interior: "Parroquia activa.", protection: "Referencia COAM (ref. 4161/69).", route: 0, lat: 40.4230, lng: -3.6100 },
  { id: "c13", block: "churches", name: "Teologado e Iglesia de San Pedro Mártir (Alcobendas)", architect: "Miguel Fisac", year: "1955–1960", address: "C. del Colegio de los Dominicos, Alcobendas, 28100", barrio: "Alcobendas (fuera del término municipal)", metro: "—", bus: "Cercanías Alcobendas–S. S. de los Reyes", description: "La iglesia más célebre de Fisac. Torre monumental de 65 m con 16 pilares de hormigón armado unidos por rampa helicoidal. El revolucionario concepto 'muro dinámico/muro estático': un muro curvo liso guía la mirada al altar mientras un muro de textura áspera admite luz dorada filtrada. Esculturas de Pablo Serrano y José Luis Sánchez.", interior: "Comunidad dominica semi-privada. Visitas con acuerdo previo; el complejo abre para celebraciones litúrgicas.", protection: "BIC (Monumento) por la Comunidad de Madrid.", route: 0, lat: 40.5400, lng: -3.6400 },
  { id: "c14", block: "churches", name: "Parroquia de San Eduardo", architect: "Luis Cubillo de Arteaga", year: "c. 1973–1979", address: "C. General Margallo, 6, 28020", barrio: "Berruguete, Tetuán", metro: "Tetuán (L1)", bus: "", description: "Iglesia brutalista poco conocida encajada entre medianeras en un bloque residencial: su austero diseño funcional moderno iguala la altura de los edificios de viviendas circundantes, convirtiéndola en un descubrimiento sorprendente en el paisaje cotidiano de Tetuán.", interior: "Parroquia activa. Abierta en horarios de misa (habitualmente 11:30 y 19:30).", protection: "Sin protección formal.", route: 0, lat: 40.4610, lng: -3.7010 },
  { id: "c15", block: "churches", name: "Parroquia de la Santísima Trinidad", architect: "Jaime Ferrater Ramoneda (estructura original); Perea, Ruiz Bernal, Vallhonrat (reforma brutalista)", year: "Mediados s. XX (original); reforma brutalista años 80, completada en dos décadas", address: "C. Martínez Villergas, 8, 28027", barrio: "Ciudad Lineal", metro: "Barrio de la Concepción (L7)", bus: "", description: "Construida sobre una ambiciosa iglesia inacabada: los arquitectos tallaron un vacío en forma de cruz en el viejo hormigón, creando cuatro brazos que abren el templo en todas direcciones. La fachada presenta un gran panel que representa la Trinidad mediante tres agujeros de formas diferentes. Publicada en El Croquis.", interior: "Parroquia activa. Abierta para culto y en horario de despacho parroquial.", protection: "Publicada en El Croquis.", route: 0, lat: 40.4380, lng: -3.6310 },
  { id: "c16", block: "churches", name: "Iglesia del Santísimo Sacramento", architect: "José María de la Vega Samper", year: "1966–1970", address: "C. Alcalde Sáinz de Baranda, 3, 28009", barrio: "Pacífico, Retiro", metro: "Sáinz de Baranda (L6, L9)", bus: "", description: "Dos torres piramidales de 42 m flanquean una nave masiva a dos aguas con un friso de Cristo con los brazos extendidos en la fachada. La audaz geometría triangular simboliza la Santísima Trinidad y convierte a esta iglesia en una de las más dramáticamente verticales del Madrid de los 60.", interior: "Iglesia activa (Padres Sacramentinos). Abierta en horarios de misa y confesión.", protection: "Sin protección formal.", route: 0, lat: 40.4095, lng: -3.6695 },
  { id: "c17", block: "churches", name: "Parroquia de San Isidoro y San Pedro Claver", architect: "Rodolfo García-Pablos González-Quijano y Rodolfo García-Pablos Ripoll (padre e hijo)", year: "1970–1971", address: "C. Villa de Pons, 12–14, 28033", barrio: "Pinar del Rey, Hortaleza", metro: "Pinar del Rey (L8)", bus: "", description: "Iglesia rigurosamente modular sobre retícula de 5×5 m: volúmenes entrelazados de ladrillo silíceo descienden en altura como un zigurat escalonado, con unidades prefabricadas de hormigón para ventanas perforando la mampostería.", interior: "Parroquia activa. Abierta para culto.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4730, lng: -3.6420 },

  // LIBRO: Arquitectura residencial
  { id: "b33", block: "brutalist", name: "Torres Blancas", architect: "Francisco Javier Sáenz de Oíza", year: "1964–1969", address: "Av. de América, 37 / C. Corazón de María, 2, 28002", barrio: "Prosperidad, Chamartín", metro: "Av. de América (L4, L6, L7, L9)", bus: "", description: "Torre orgánica de hormigón armado de 71 m y 23 plantas que evoca un árbol gigante: cilindros huecos se ramifican en balcones-terraza con jardineras integradas. Sáenz de Oíza fusionó el brutalismo con un organicismo wrightiano sin precedentes en Europa. A pesar de su nombre, nunca fue blanca: el hormigón visto exhibe su materialidad desnuda como manifiesto del béton brut.", interior: "Residencial privado. Restaurante en planta baja (accesible). Terraza-mirador en azotea ocasionalmente abierta en Open House Madrid.", protection: "BIC (Bien de Interés Cultural) desde 2017.", route: 0, lat: 40.4398, lng: -3.6720 },
  { id: "b34", block: "brutalist", name: "Torre de Valencia", architect: "Javier Carvajal Ferrer", year: "1970–1973", address: "Av. de Menéndez Pelayo, 9, 28009", barrio: "Ibiza, Retiro", metro: "Ibiza (L9)", bus: "", description: "Rascacielos residencial de 94 m y 27 plantas que provocó una de las mayores polémicas urbanísticas del tardofranquismo al interponerse en la visual de la Puerta de Alcalá desde el Retiro. Fachada de hormigón visto con profundas logias retranqueadas que generan un juego rítmico de luces y sombras de enorme plasticidad brutalista.", interior: "Edificio residencial. Solo visible desde el exterior.", protection: "Base de datos SOS Brutalism. Sin BIC formal.", route: 0, lat: 40.4215, lng: -3.6795 },
  { id: "b35", block: "brutalist", name: "Edificio Girasol", architect: "José Antonio Coderch de Sentmenat", year: "1964–1966", address: "C. José Ortega y Gasset, 23 / C. Lagasca, 90, 28006", barrio: "Castellana, Salamanca", metro: "Núñez de Balboa (L5, L9)", bus: "", description: "Viviendas de lujo con planta en forma de peine cuyos volúmenes giran en diagonal hacia la calle Lagasca para captar la máxima luz solar a lo largo del día — de ahí su nombre. Coderch, maestro catalán del organicismo mediterráneo, rompió la manzana del Ensanche con una fachada de lamas de aluminio y terrazas escalonadas que aún hoy resulta radicalmente moderna.", interior: "Edificio residencial privado. Solo exterior.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4305, lng: -3.6830 },
  { id: "b36", block: "brutalist", name: "Complejo Residencial Galaxia", architect: "Antonio Lamela Martínez", year: "1966–1974", address: "C. Isaac Peral, 4, 28015", barrio: "Gaztambide, Chamberí", metro: "Moncloa (L3, L6)", bus: "", description: "Macromanzana brutalista de más de 20.000 m² con accesos por cuatro calles, organizada en módulos de hormigón que forman un perímetro cerrado como barrera acústica. Una gran rampa helicoidal en el patio central rompe la rigidez cartesiana e introduce un espacio fluido entre niveles, usos y velocidades.", interior: "Residencial y comercial. Zonas comerciales accesibles. Parking público.", protection: "Sin protección formal.", route: 0, lat: 40.4350, lng: -3.7180 },
  { id: "b37", block: "brutalist", name: "Pirámides de Potosí", architect: "Luis Gutiérrez Soto", year: "1972–1986", address: "C. Potosí, 10 / C. Bolivia, 28016", barrio: "Hispanoamérica, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Tres bloques residenciales monolíticos con perfil escalonado piramidal, terrazas corridas y jardineras que recuerdan templos aztecas trasladados al norte de la Castellana. La inclinación de las fachadas garantiza la entrada de luz natural incluso en las terrazas inferiores. Gutiérrez Soto no llegó a ver terminada su última gran obra, completada nueve años después de su muerte.", interior: "Edificio residencial. Solo exterior.", protection: "Sin protección formal.", route: 0, lat: 40.4575, lng: -3.6880 },
  { id: "b38", block: "brutalist", name: "Edificio Princesa", architect: "Fernando Higueras Díaz, Antonio Miró Valverde", year: "1967–1975", address: "C. Santa Cruz de Marcenado, 1-4 / C. del Acuerdo, 34, 28015", barrio: "Universidad, Centro", metro: "San Bernardo (L2, L4)", bus: "", description: "Bloque de 261 viviendas militares en hormigón visto concebido como un jardín vertical: amplios balcones volados con jardineras integradas donde la vegetación trepa y cuelga, creando un oasis verde en pleno centro. Higueras se inspiró en ruinas aztecas para lograr una arquitectura donde hormigón y naturaleza mantienen un diálogo constante.", interior: "Residencial. Algunas viviendas disponibles como apartamentos turísticos de lujo. Exterior libremente visible.", protection: "Sin protección formal. Destacado en múltiples guías de brutalismo madrileño.", route: 0, lat: 40.4295, lng: -3.7105 },
  { id: "b39", block: "brutalist", name: "Edificio L.G.M.", architect: "Antonio Vallejo Acevedo, José Luis González Cruz", year: "1968", address: "C. Juan Ramón Jiménez, 22, 28036", barrio: "Cuzco, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Bloque residencial brutalista de elegante pórtico de hormigón que, paradójicamente, agranda y aligera los volúmenes en lugar de aplastarlos. Su paleta de grises, marrones y tonos rojizos contrasta con el verde del jardín. Muchos de sus residentes originales fueron arquitectos, y el edificio sirvió como escenario de un thriller político cinematográfico.", interior: "Edificio residencial. Solo exterior.", protection: "Sin protección formal. Destacado por @madrid_brutalism.", route: 0, lat: 40.4570, lng: -3.6910 },
  { id: "b40", block: "brutalist", name: "Bloque de viviendas en Juan de Haro Piñar", architect: "Autor desconocido", year: "c. 1969", address: "C. Juan de Haro Piñar, 28036", barrio: "Cuzco, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Bloque residencial brutalista descubierto por el arquitecto Alejandro García Alcántara mientras recorría Madrid en bicicleta. Sus elementos salientes a modo de gárgolas y la rotundidad de sus volúmenes de hormigón lo convierten en una pieza insólita del brutalismo doméstico madrileño, casi desconocida fuera de los círculos especializados.", interior: "Edificio residencial. Solo exterior.", protection: "Sin protección formal. Incluido en el libro Madrid Brutal (2023).", route: 0, lat: 40.4565, lng: -3.6895 },
  { id: "b41", block: "brutalist", name: "Viviendas Carrión", architect: "José Luis González Cruz", year: "c. 1970", address: "C. Doctor Esquerdo, 169, 28007", barrio: "Niño Jesús, Retiro", metro: "Pacífico (L1, L6)", bus: "", description: "Bloque residencial brutalista de hormigón visto con fachada modulada en profundos retranqueos y balcones corridos que crean un ritmo vertical contundente. La honestidad constructiva y la expresividad plástica del hormigón armado reflejan la influencia directa de las unités d'habitation corbuserianas en el tejido urbano madrileño.", interior: "Edificio residencial. Solo exterior.", protection: "Sin protección formal.", route: 0, lat: 40.4090, lng: -3.6740 },
  { id: "b42", block: "brutalist", name: "Torre de viviendas en El Pinar de Chamartín", architect: "Juan Castañón Fariña, José María Laguna Martínez", year: "c. 1968–1972", address: "C. Arturo Soria, 319-321, 28033", barrio: "Costillares, Ciudad Lineal", metro: "Pinar de Chamartín (L1, L4)", bus: "", description: "Torres residenciales de 23 plantas con planta en Y que albergan seis viviendas por piso en torno a un núcleo central de comunicaciones verticales. Las fachadas brutalistas combinan muros de hormigón visto con paneles de bloque prefabricado, quebrando las esquinas con múltiples retranqueos y celosías metálicas de acero que marcan los ángulos interiores.", interior: "Edificio residencial. Solo exterior.", protection: "Catalogado en la Guía de Arquitectura de Madrid (COAM).", route: 0, lat: 40.4780, lng: -3.6480 },
  { id: "b43", block: "brutalist", name: "Conjunto Residencial Vista Hermosa", architect: "Antoni Perpiñà Sebrià, José Luis González Cruz", year: "1975", address: "C. Duque de Sesto, 39-41, 28009", barrio: "Ibiza, Retiro", metro: "Ibiza (L9)", bus: "", description: "Cuatro bloques residenciales agrupados en un prisma denso elevado sobre potentes pantallas-pilares de hormigón que liberan la planta baja. Concebido a la manera plástica de las unités d'habitation de Le Corbusier, con estructura de hormigón armado vista y paneles con celosías que modulan la luz.", interior: "Edificio residencial. Solo exterior.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4215, lng: -3.6745 },
  { id: "b44", block: "brutalist", name: "Casa Carvajal", architect: "Javier Carvajal Ferrer", year: "1964–1966", address: "C. Talavera, 7, Urb. Somosaguas, 28223 Pozuelo de Alarcón", barrio: "Somosaguas, Pozuelo de Alarcón", metro: "—", bus: "Bus A desde Moncloa", description: "Vivienda unifamiliar que Carvajal proyectó para su propia familia: volúmenes rotundos de hormigón visto y ladrillo articulados en torno a patios que dialogan con el paisaje de la sierra. Su presencia escultórica sirvió de escenario para La Madriguera de Carlos Saura (1969) y obtuvo el Premio Fritz Schumacher de la Universidad de Hannover en 1968.", interior: "Residencia privada. Visitable ocasionalmente en jornadas de puertas abiertas y Open House Madrid.", protection: "BIC (Bien de Interés Cultural) desde 2022.", route: 0, lat: 40.4185, lng: -3.7870 },

  // LIBRO: Arquitectura religiosa
  { id: "c18", block: "churches", name: "Parroquia de Nuestra Señora de Guadalupe", architect: "Enrique de la Mora y Palomar, José Ramón Azpiazu (arqs.); Félix Candela, José Antonio Torroja (ings.)", year: "1962–1965", address: "C. Puerto Rico, 1, 28016", barrio: "Hispanoamérica, Chamartín", metro: "Concha Espina (L9)", bus: "", description: "Primera obra de un arquitecto mexicano en España: planta octogonal inscrita en un círculo de 54 m de diámetro cubierta por ocho paraboloides hiperbólicos de hormigón de apenas 4 cm de espesor, apoyados en solo cuatro pilares interiores. La silueta resultante, semejante a un sombrero mexicano, constituye una proeza estructural de Candela y Torroja que traduce al hormigón laminar la tradición constructiva mexicana.", interior: "Parroquia activa. Abierta para misa y visitas en horario de culto.", protection: "Registro Docomomo Ibérico (Nivel A). Catálogo COAM.", route: 0, lat: 40.4524, lng: -3.6747 },
  { id: "c19", block: "churches", name: "Basílica Hispanoamericana de Nuestra Señora de la Merced", architect: "Francisco Javier Sáenz de Oíza, Luis Laorga Gutiérrez", year: "1949–1965", address: "C. Edgar Neville, 23, 28020", barrio: "Cuatro Caminos, Tetuán", metro: "Nuevos Ministerios (L6, L8, L10)", bus: "", description: "Ganadora de un concurso en 1949, esta basílica de planta basilical alargada se materializó en bloques prefabricados de hormigón, sistema pionero en España, culminando en una cúpula monumental de 20 m de diámetro. La larguísima ejecución (16 años) provocó la ruptura entre sus autores, pero hoy se estudia como hito del brutalismo sacro madrileño.", interior: "Parroquia activa. Abierta para culto diario.", protection: "Registro Docomomo Ibérico. Guía COAM.", route: 0, lat: 40.4495, lng: -3.6970 },
  { id: "c20", block: "churches", name: "Parroquia de Nuestra Señora del Rosario de Filipinas", architect: "Cecilio Sánchez-Robles Tarín (reforma: Manuel Mateo Sanz, 1989)", year: "1967–1970", address: "C. Conde de Peñalver, 40, 28006", barrio: "Lista, Salamanca", metro: "Lista (L4)", bus: "", description: "Conjunto brutalista de iglesia, convento dominico y oficinas resuelto en hormigón visto y aluminio al natural, con volúmenes de gran rotundidad formal que evocan el Palacio de la Asamblea de Chandigarh de Le Corbusier. Incomprendida durante décadas por su ruptura radical con la estética del barrio de Salamanca, hoy se reivindica como tesoro oculto del brutalismo madrileño.", interior: "Parroquia activa (Padres Dominicos). Abierta para culto.", protection: "Registro Docomomo Ibérico. Guía COAM.", route: 0, lat: 40.4292, lng: -3.6751 },
  { id: "c21", block: "churches", name: "Parroquia de Santa Ana y la Esperanza", architect: "Miguel Fisac", year: "1965–1966", address: "C. Cañada, 35, 28030", barrio: "Vinateros, Moratalaz", metro: "Artilleros (L9)", bus: "", description: "Primer templo de Fisac diseñado según las directrices del Concilio Vaticano II: planta en abanico con el altar centrado para la participación activa de los fieles. Muros portantes de hormigón armado visto y cubierta con las patentadas 'vigas hueso' pretensadas de Fisac, componiendo un conjunto de volúmenes rectangulares escalonados de austeridad expresiva.", interior: "Parroquia activa. Despacho: lun–vie mañanas y tardes.", protection: "Registro Docomomo Ibérico. Bien Catalogado por la Comunidad de Madrid.", route: 0, lat: 40.4054, lng: -3.6450 },
  { id: "c22", block: "churches", name: "Parroquia de Nuestra Señora del Buen Suceso", architect: "Manuel del Río Martínez, Ignacio Ferrero Ruiz de la Prada, Juan Hernández Ferrero", year: "1975–1982", address: "C. Princesa, 43, 28008", barrio: "Argüelles, Moncloa-Aravaca", metro: "Argüelles (L3, L4, L6)", bus: "", description: "Tercera iglesia del Buen Suceso, integrada en una manzana residencial y comercial entre las calles Princesa, Quintana, Tutor y Buen Suceso. Su fachada revestida de acero inoxidable le valió el apodo popular 'Nuestra Señora de Magefesa'. Solución urbana audaz que funde templo y bloque de viviendas bajo un lenguaje metálico y brutalista insólito en la arquitectura religiosa madrileña.", interior: "Parroquia activa. Abierta para culto diario.", protection: "Sin protección formal.", route: 0, lat: 40.4293, lng: -3.7158 },

  // LIBRO: Arquitectura escolar
  { id: "b45", block: "brutalist", name: "Facultad de Ciencias de la Información (UCM)", architect: "José María Laguna Martínez, Juan Castañón Fariña (fase 2: Manuel Briñas Coronado)", year: "1972–1979", address: "Avda. Complutense, s/n, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Uno de los ejemplos más emblemáticos del brutalismo madrileño: volúmenes rotundos de hormigón visto con geometrías angulosas y texturas rugosas que le han valido el apodo popular de 'el búnker'. Construido en dos fases, el conjunto expresa con contundencia la honestidad constructiva del béton brut, rechazando todo ornamento en favor de la masa y la estructura desnuda.", interior: "Edificio universitario público. Accesible en horario académico (L-V 8:00–21:00). Ha participado en la Semana de la Arquitectura de Madrid.", protection: "Sin BIC formal. Registro Docomomo Ibérico. Catalogado por COAM.", route: 0, lat: 40.4449, lng: -3.7288 },
  { id: "b46", block: "brutalist", name: "Facultad de Ciencias Biológicas y Geológicas (UCM)", architect: "Fernando Moreno Barberá", year: "1964–1969", address: "C. José Antonio Novais, 12, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Dos prismas de hormigón visto — uno horizontal para aulas y espacios comunes, uno vertical de 13 plantas para laboratorios y despachos — configuran el edificio más alto de la Ciudad Universitaria. Las ventanas parasol minimizan la incidencia solar directa, recurso habitual en la obra educativa de Moreno Barberá.", interior: "Edificio universitario público. Accesible en horario académico.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4486, lng: -3.7254 },
  { id: "b47", block: "brutalist", name: "Colegio Asunción Cuestablanca", architect: "Miguel Fisac Serna", year: "1965–1968", address: "C. de la Asunción Cuestablanca, 11, 28050", barrio: "Sanchinarro, Hortaleza", metro: "Las Tablas (ML1)", bus: "152, 155, 156, 157", description: "Conjunto de pabellones de hormigón visto cubiertos con las inconfundibles vigas-hueso de Fisac, adaptados a un solar de topografía irregular con desniveles de hasta 12 metros. Las aulas se escalonan y conectan mediante rampas que hacen fluida la transición entre niveles, mientras cada pabellón mantiene independencia visual.", interior: "Colegio privado activo. No accesible en horario escolar. Exterior visible desde la calle.", protection: "Registro Docomomo Ibérico. Catalogado en Fundación Fisac.", route: 0, lat: 40.4948, lng: -3.6588 },
  { id: "b48", block: "brutalist", name: "Liceo Francés de Madrid", architect: "Pierre Sonrel, Jean Duthilleul, Alfredo Rodríguez Orgaz", year: "1968–1971", address: "Plaza del Liceo, 1, 28043", barrio: "Conde de Orgaz, Hortaleza", metro: "Esperanza (L4)", bus: "", description: "Campus brutalista de 10 hectáreas concebido como una pequeña ciudad universitaria: grandes columnas de hormigón armado visto generan profundos pórticos en sombra, unidos en cubierta por bóvedas rebajadas de cañón del mismo material. La sinceridad constructiva no descuida la iluminación natural, logrando un brutalismo mediterráneo matizado por la vegetación del parque circundante.", interior: "Centro educativo privado. No accesible al público general. Exterior parcialmente visible desde la plaza.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4565, lng: -3.6340 },
  { id: "b49", block: "brutalist", name: "Facultad de Humanidades de la UNED", architect: "Juan de Haro Piñar", year: "1965–1969", address: "Paseo Senda del Rey, 7, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Originalmente construido como Colegio Mayor Siao-Sin, este volumen introvertido y macizo de hormigón visto fue reconvertido en sede de la Facultad de Humanidades de la UNED. La arquitectura de Juan de Haro se caracteriza por su rotundidad brutalista: edificios sustanciales y cerrados sobre sí mismos, donde la masa de hormigón predomina sobre el hueco.", interior: "Edificio universitario. Accesible en horario académico y durante eventos de la UNED.", protection: "Sin protección formal.", route: 0, lat: 40.4440, lng: -3.7310 },
  { id: "b50", block: "brutalist", name: "Colegio Santo Ángel de la Guarda", architect: "Juan Gómez y González de la Buelga", year: "1965", address: "C. Alcalá, 587, 28022", barrio: "Canillejas, San Blas-Canillejas", metro: "Canillejas (L5)", bus: "", description: "Estructura de hormigón armado visto con paños de relleno de ladrillo silíceo, poderosos testeros volados sobre ménsulas y marquesinas ondulantes de acceso que demuestran las posibilidades plásticas del hormigón. Un ejemplo poco conocido pero notable del brutalismo educativo madrileño, donde la retícula estructural queda completamente expuesta y legible en fachada.", interior: "Colegio privado activo. No accesible al público general. Exterior visible desde Calle Alcalá.", protection: "Catalogado en guía COAM de arquitectura de Madrid.", route: 0, lat: 40.4520, lng: -3.6130 },
  { id: "b51", block: "brutalist", name: "Facultad de Estudios Estadísticos (UCM)", architect: "Miguel Fisac Serna", year: "1953–1957", address: "Avda. Puerta de Hierro, 1, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Ciudad Universitaria (L6)", bus: "", description: "Originalmente Centro de Formación del Profesorado de Enseñanza Media y Profesional, es una de las intervenciones más relevantes de Fisac en la Ciudad Universitaria. Estructura de hormigón visto con paños de ladrillo y marquesinas experimentales ejecutadas con encofrados de escayola, un laboratorio constructivo donde Fisac ensayó sus innovaciones en la relación entre forma y estructura.", interior: "Edificio universitario público. Accesible en horario académico.", protection: "Registro Docomomo Ibérico. Catalogado por COAM.", route: 0, lat: 40.4468, lng: -3.7267 },

  // LIBRO: Arquitectura institucional
  { id: "b52", block: "brutalist", name: "Sede del SEPE (Servicio Público de Empleo Estatal)", architect: "Desconocido (Ministerio de Trabajo)", year: "1978–1982", address: "C. de la Condesa de Venadito, 9, 28027", barrio: "San Pascual, Ciudad Lineal", metro: "Suanzes (L5)", bus: "38, 48, 109", description: "Bloque administrativo de volumetría rotunda y fachadas de hormigón prefabricado con ventanales modulares repetitivos, representativo de la arquitectura institucional tardofranquista y transicional. Su planta rectangular y organización en bandas responden a una lógica funcionalista austera.", interior: "Oficinas gubernamentales. Sin acceso público general.", protection: "Sin protección patrimonial conocida.", route: 0, lat: 40.4350, lng: -3.6260 },
  { id: "b53", block: "brutalist", name: "Sede del Tribunal Constitucional", architect: "Antonio Bonet Castellana, Francisco González Valdés", year: "1975–1980", address: "C. de Domenico Scarlatti, 6, 28003", barrio: "Vallehermoso, Chamberí", metro: "Islas Filipinas (L7)", bus: "2, 44, 149", description: "Edificio de planta circular compuesto por cuatro cuerpos cilíndricos interconectados, el principal de siete plantas, con una fachada-cortina de chapa de aluminio anodizado en bronce y perfilería extruida que le confiere un aspecto escultórico singular. Originalmente proyectado para Previsión Sanitaria Nacional, fue adaptado como sede del Tribunal Constitucional en 1981.", interior: "Sede institucional. Visitas guiadas ocasionales organizadas por el Tribunal.", protection: "Sin BIC. Edificio institucional protegido por su uso.", route: 0, lat: 40.4380, lng: -3.7080 },
  { id: "b54", block: "brutalist", name: "Complejo Cuzco", architect: "Antonio Perpiñá Sebriá", year: "1964–1980", address: "Paseo de la Castellana, 160–162, 28046", barrio: "Castillejos, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Complejo ministerial brutalista articulado en torno a una torre de 25 plantas y 100 metros de altura junto a edificios horizontales de hasta 13 pisos, con fuerte influencia del brutalismo inglés y la arquitectura norteamericana del período. Las fachadas emplean piezas prefabricadas de hormigón con textura marcada que generan un ritmo serial contundente.", interior: "Edificio gubernamental. Sin acceso público general; torre visible desde la Castellana.", protection: "Sin BIC formal. Catalogado como conjunto de interés.", route: 3, lat: 40.4583, lng: -3.6894 },
  { id: "b55", block: "brutalist", name: "Instituto del Patrimonio Cultural de España 'Corona de Espinas'", architect: "Fernando Higueras, Antonio Miró Valverde", year: "1965–1985", address: "C. del Pintor El Greco, 4, 28040", barrio: "Ciudad Universitaria, Moncloa-Aravaca", metro: "Moncloa (L3, L6)", bus: "46, 82, 132, G", description: "Edificio circular de hormigón armado visto inscrito en un radio de 40 metros y dividido en 30 secciones radiales que generan una cornisa dentada, origen de su apodo popular 'Corona de Espinas'. Cuatro plantas concéntricas conectadas por dos núcleos de escaleras y ascensores conforman un espacio de expresionismo orgánico sin parangón en la arquitectura española. Obra maestra de Fernando Higueras, hoy alberga los talleres de restauración del patrimonio nacional.", interior: "Visitas guiadas periódicas y jornadas de puertas abiertas (Open House Madrid). Talleres de restauración parcialmente visitables.", protection: "BIC (Bien de Interés Cultural) desde 2001.", route: 0, lat: 40.4411, lng: -3.7348 },
  { id: "b56", block: "brutalist", name: "Servicios Centrales del Instituto Nacional de la Seguridad Social", architect: "Desconocido (Ministerio de Trabajo y Seguridad Social)", year: "c. 1975–1980", address: "C. del Padre Damián, 4–6, 28036", barrio: "Hispanoamérica, Chamartín", metro: "Cuzco (L10)", bus: "", description: "Edificio administrativo de nueve plantas y planta tripartita con tres alas por nivel, representativo de la arquitectura institucional brutalista de los años setenta en Madrid. Sus fachadas modulares y la volumetría masiva de hormigón reflejan la escala monumental de los grandes programas de la Seguridad Social española.", interior: "Oficinas gubernamentales del INSS. Sin acceso público.", protection: "Sin protección patrimonial conocida.", route: 0, lat: 40.4570, lng: -3.6860 },

  // LIBRO: Arquitectura administrativa y comercial
  { id: "b57", block: "brutalist", name: "Sede de la UGT", architect: "Antonio Vallejo Acevedo, Santiago de la Fuente Viqueira", year: "1970–1977", address: "Avenida de América, 25, 28002", barrio: "Prosperidad, Chamartín", metro: "Cartagena (L7)", bus: "", description: "Imponente sede sindical de hormigón visto concebida originalmente para la Organización Sindical del régimen franquista y posteriormente asignada a la UGT. Volumen monolítico de severidad formal rotunda con fachadas reticulares de hormigón que enfatizan la horizontalidad y el peso institucional.", interior: "Edificio sindical. Interior no visitable. Exterior libremente visible desde Avenida de América.", protection: "Sin protección formal.", route: 0, lat: 40.4385, lng: -3.6700 },
  { id: "b58", block: "brutalist", name: "Edificio Beatriz", architect: "Eleuterio Población Knappe", year: "1966–1975", address: "C. José Ortega y Gasset, 29, 28006", barrio: "Castellana, Salamanca", metro: "Núñez de Balboa (L5, L9)", bus: "", description: "Primer edificio en España con fachada portante que forma parte de la estructura, encargado por el Banco Popular tomando como modelo la Banca Lambert de Bruselas de Gordon Bunshaft. Muro cortina de hormigón prefabricado y vidrio oscuro que confiere al volumen una presencia monumental y sobria.", interior: "Espacio de eventos El Beatriz Madrid. Accesible durante eventos y exposiciones.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4310, lng: -3.6820 },
  { id: "b59", block: "brutalist", name: "Edificio Caracas", architect: "Javier Carvajal Ferrer, Juan Manuel Ruiz de la Prada", year: "1968–1970", address: "C. de Caracas, 4, 28010", barrio: "Almagro, Chamberí", metro: "Rubén Darío (L5)", bus: "", description: "Lenguaje cubista de volúmenes prismáticos maclados donde el chaflán y las ventanas convencionales desaparecen, sustituidos por un concierto rítmico de llenos y vacíos. Las fachadas se revisten con losas moduladas de hormigón blanco prefabricado que Carvajal emplearía después en la Torre de Valencia.", interior: "Edificio de oficinas. Solo exterior.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4355, lng: -3.6925 },
  { id: "b60", block: "brutalist", name: "Edificio Pirámide", architect: "Antonio Lamela", year: "1974–1979", address: "Paseo de la Castellana, 31, 28046", barrio: "Almagro, Chamberí", metro: "Rubén Darío (L5)", bus: "", description: "Nueve plantas sobre rasante más cuatro sótanos cuya forma de tronco piramidal invertido fue condicionada por las limitaciones municipales de retranqueos. Erigido sobre los terrenos del antiguo palacio de los Condes de San Bernardo, su silueta escalonada en hormigón y vidrio oscuro constituye una de las presencias más singulares de la Castellana.", interior: "Oficinas privadas. No visitable. Exterior visible desde Castellana.", protection: "Sin protección formal.", route: 0, lat: 40.4314, lng: -3.6900 },
  { id: "b61", block: "brutalist", name: "Edificio Vega", architect: "Miguel Fisac", year: "1964–1966", address: "C. Velázquez, 157 (esq. C. Doctor Arce), 28002", barrio: "Hispanoamérica, Chamartín", metro: "República Argentina (L6)", bus: "", description: "La parcela triangular condicionó una planta en estrella de tres cuerpos rectangulares de cinco alturas articulados por un núcleo central de comunicaciones. Fisac empleó sus características bandejas curvas de hormigón armado en fachada para alojar fan-coils y persianas, confiriendo al volumen un marcado carácter horizontal.", interior: "Edificio de oficinas. Solo exterior.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4530, lng: -3.6780 },
  { id: "b62", block: "brutalist", name: "Edificio IBM", architect: "Miguel Fisac", year: "1966–1968", address: "Paseo de la Castellana, 4, 28046", barrio: "Recoletos, Salamanca", metro: "Colón (L4)", bus: "", description: "Oficinas de planta libre tras una fachada-biombo de piezas huecas de hormigón pretensado en sección de bumerán de solo dos centímetros de espesor, rellenas de aislamiento. La protección solar del poniente motivó este cerramiento vertical permeable que evoca el ritmo de las fachadas decimonónicas del centro de Madrid.", interior: "Edificio de oficinas. Solo exterior visible desde Castellana y calle Hermosilla.", protection: "Registro Docomomo Ibérico.", route: 0, lat: 40.4230, lng: -3.6880 },
  { id: "b63", block: "brutalist", name: "Instituto de Química Orgánica (CSIC)", architect: "Miguel Fisac", year: "1963–1964", address: "C. Juan de la Cierva, 3, 28006", barrio: "Niño Jesús, Retiro", metro: "Atocha (L1)", bus: "", description: "Edificio de investigación dentro del complejo del CSIC donde Fisac experimentó con hormigón visto como material expresivo principal. La composición volumétrica austera y funcional refleja la vocación científica del programa, con laboratorios organizados en torno a un núcleo de comunicaciones.", interior: "Centro de investigación activo. Acceso restringido. Ha participado en Open House Madrid.", protection: "Sin protección formal.", route: 0, lat: 40.4095, lng: -3.6895 },
  { id: "b64", block: "brutalist", name: "Centro de Clasificación Postal de Madrid-Chamartín", architect: "José Luis González Cruz", year: "1971–1975", address: "C. Hiedra, s/n (Estación de Chamartín), 28036", barrio: "Chamartín", metro: "Chamartín (L1, L10)", bus: "", description: "Complejo postal brutalista de tres cuerpos diferenciados junto a las vías de Chamartín: estación postal sobre las vías férreas, nave de clasificación de correspondencia y bloque administrativo al sureste. Grandes pórticos de hormigón armado salvan luces considerables, expresando con rotundidad la función industrial del correo.", interior: "Instalación postal activa. No visitable.", protection: "Sin protección formal.", route: 0, lat: 40.4730, lng: -3.6810 },
  { id: "b65", block: "brutalist", name: "Centro de Estudios Hidrográficos (CEDEX)", architect: "Miguel Fisac", year: "1960–1963", address: "Paseo Bajo de la Virgen del Puerto, 3, 28005", barrio: "Imperial, Arganzuela", metro: "Príncipe Pío (L6, L10, R)", bus: "25, 31, 33, 39, 41, 50, 62, 65, 138", description: "Una de las obras más singulares de Fisac: el laboratorio hidráulico se cubre con vigas pretensadas 'en hueso' de 22 metros de luz que permiten iluminación cenital indirecta, las primeras de hormigón pretensado con armaduras postesas de Madrid. El paralelepípedo de siete plantas alberga oficinas y salas de reuniones con mobiliario también diseñado por Fisac.", interior: "Visitable con cita previa (visitasceh@cedex.es). Visitas guiadas jueves 12:00 h. Participa en Open House Madrid y Semana de la Arquitectura.", protection: "BIC (Bien de Interés Cultural) desde 2023.", route: 0, lat: 40.4095, lng: -3.7175 },
  { id: "b66", block: "brutalist", name: "Edificio de los Cubos (Edificio AGF)", architect: "Michel Andrault, Pierre Parat, Aydin Guvan, Alain Capieu (dir. obra: Luis de la Rica)", year: "1974–1981", address: "C. Albacete, 5, 28027", barrio: "San Pascual, Ciudad Lineal", metro: "Ventas (L2, L5)", bus: "", description: "Seis prismas rectangulares de vidrio oscuro suspendidos sobre dieciséis pilares de hormigón visto junto a la M-30, composición que participa del brutalismo lecorbusieriano pero se identifica más con el metabolismo japonés de Kenzō Tange. Diseñado por un equipo francés para la aseguradora AGF. Rehabilitado integralmente en 2017–2020 con certificación LEED Gold.", interior: "Edificio de oficinas. Solo exterior visible desde la M-30.", protection: "Sin protección formal.", route: 0, lat: 40.4310, lng: -3.6490 },
  { id: "b67", block: "brutalist", name: "Antigua Embajada del Reino Unido", architect: "W. S. Bryant, Luis Blanco-Soler", year: "1966", address: "C. Fernando el Santo, 16, 28010", barrio: "Almagro, Chamberí", metro: "Alonso Martínez (L4, L5, L10)", bus: "", description: "Singular planta circular con patio central que evoca la tipología de una plaza de toros, construida en hormigón y granito gris tras la demolición del palacete del Marqués de Álava. Fue sede diplomática británica de 1966 a 2009, cuando la embajada se trasladó a Torre Espacio.", interior: "Espacio de eventos (ha albergado Casa Decor 2013 y exposiciones de arte). Accesible durante eventos.", protection: "Sin protección formal.", route: 0, lat: 40.4295, lng: -3.6935 },

  // LIBRO: Otras arquitecturas
  { id: "b68", block: "brutalist", name: "Hospital Universitario La Paz", architect: "Martín José Marcide Odriozola", year: "1964", address: "Paseo de la Castellana, 261, 28046", barrio: "El Goloso, Fuencarral-El Pardo", metro: "Begoña (L10)", bus: "67, 124, 134", description: "Megaestructura hospitalaria de planta en peine con pabellones paralelos de hormigón visto y ladrillo conectados por corredores aéreos, uno de los mayores complejos sanitarios de España. Su torre maternal de diecisiete plantas domina el tramo norte de la Castellana con una rotundidad volumétrica propia del brutalismo institucional de los sesenta.", interior: "Hospital público. Acceso libre a zonas comunes y vestíbulos principales.", protection: "Sin protección formal.", route: 0, lat: 40.4812, lng: -3.6868 },
  { id: "b69", block: "brutalist", name: "Depósito Elevado del Canal de Isabel II", architect: "Dirección Técnica del Canal de Isabel II", year: "1952–1954", address: "Plaza de Castilla, s/n (esquina Bravo Murillo), 28046", barrio: "Castillejos, Tetuán", metro: "Plaza de Castilla (L1, L9, L10)", bus: "5, 27, 42, 49, 147", description: "Tanque cilíndrico de hormigón armado de 36 metros de altura y 2.500 m³ de capacidad, alzado sobre un fuste troncocónico que recuerda una copa brutalista descomunal. Su silueta rotunda e industrial marca la entrada norte de la Castellana como un hito involuntariamente escultórico. Reconvertido en sala de exposiciones fotográficas del Canal de Isabel II desde 1986.", interior: "Sala de exposiciones del Canal de Isabel II. Entrada gratuita. Horario: mar–dom 11:00–14:00 y 17:00–20:30.", protection: "Catalogado por el Ayuntamiento de Madrid. Registro Docomomo Ibérico.", route: 0, lat: 40.4661, lng: -3.6895 },
  { id: "b70", block: "brutalist", name: "Voladizo de la M-40 (Enlace A-2 / M-40)", architect: "Ingeniería MOPT (Ministerio de Obras Públicas y Transportes)", year: "c. 1990–1992", address: "Enlace M-40 con A-2 (Autovía de Barcelona), altura de Canillejas, 28022", barrio: "Canillejas, San Blas-Canillejas", metro: "Canillejas (L5)", bus: "", description: "Espectacular voladizo curvo de hormigón postensado que salva el cruce multinivel de la M-40 con la A-2, proyectando la calzada en el vacío con un gesto estructural de brutalidad ingenieril. Su curvatura y dimensiones lo convierten en un objeto casi escultórico, un ejemplo de infraestructura como arquitectura involuntaria.", interior: "Infraestructura viaria. Solo visible desde vehículo o a pie desde calles adyacentes.", protection: "Sin protección formal.", route: 0, lat: 40.4432, lng: -3.6120 },
  { id: "b71", block: "brutalist", name: "Zoo Aquarium de Madrid — Pabellones", architect: "Javier Carvajal Ferrer, J. A. Corrales, R. Vázquez Molezún (varios pabellones)", year: "1968–1972", address: "Casa de Campo, s/n, 28011", barrio: "Casa de Campo, Latina", metro: "Batán (L10), Casa de Campo (L10)", bus: "33", description: "Conjunto de pabellones de hormigón visto y geometrías orgánicas brutalistas diseñados por algunos de los mejores arquitectos españoles del momento, integrados en la topografía arbolada de la Casa de Campo. Destacan las cubiertas laminares y los muros curvos de la casa de fieras, que dialogan con la naturaleza desde un lenguaje de hormigón bruto.", interior: "Parque zoológico público. Entrada de pago. Horario variable según temporada.", protection: "Sin protección formal. Catalogado parcialmente en guía COAM.", route: 0, lat: 40.4108, lng: -3.7694 },
  { id: "b72", block: "brutalist", name: "Hotel VP Plaza España Design (antiguo Hotel Princesa Plaza)", architect: "Julio Cano Lasso", year: "1968–1971", address: "Plaza de España, 5, 28008", barrio: "Palacio, Centro", metro: "Plaza de España (L3, L10)", bus: "25, 39, 138, 148", description: "Torre hotelera de planta trapezoidal con fachada de hormigón prefabricado y ritmo vertical de balcones empotrados que dominan la Plaza de España. La remodelación de 2016 añadió una piel contemporánea de vidrio y acero, pero la estructura brutalista original de Cano Lasso permanece intacta bajo la nueva imagen.", interior: "Hotel de cinco estrellas. Acceso público a restaurante en azotea con vistas panorámicas a Madrid.", protection: "Sin protección formal.", route: 0, lat: 40.4236, lng: -3.7121 },
];

export default BUILDINGS;
